"""
Parameterized generator for GH965_pymc_8201.

Source PR:    https://github.com/pymc-devs/pymc/pull/8201
Source Issue: N/A

Seed varies: renames 'add_task' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH965_pymc_8201'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH965_pymc_8201'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('add_task', 'add_task' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH965_pymc_8201',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 8201,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/8201",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/progress_bar/marimo_progress.py': '#   Copyright 2025 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nfrom collections.abc import Callable\nfrom time import perf_counter\nfrom typing import Any, Self\n\nfrom pymc.progress_bar.marimo_progress_css import DEFAULT_CSS\n\n\ndef format_time(seconds: float) -> str:\n    """Format elapsed time as mm:ss or hh:mm:ss."""\n    minutes, secs = divmod(int(seconds), 60)\n    hours, minutes = divmod(minutes, 60)\n    if hours > 0:\n        return f"{hours}:{minutes:02d}:{secs:02d}"\n    return f"{minutes}:{secs:02d}"\n\n\ndef in_marimo_notebook() -> bool:\n    """Check if running inside a marimo notebook.\n\n    Returns\n    -------\n    bool\n        True if running in a marimo notebook, False otherwise.\n    """\n    try:\n        import marimo as mo\n\n        return mo.running_in_notebook()\n    except (ImportError, AttributeError):\n        return False\n\n\ndef _mo_write_internal(cell_id: str, value: object) -> None:\n    """Write to marimo cell given cell_id."""\n    from marimo._messaging.cell_output import CellChannel\n    from marimo._messaging.notification_utils import CellNotificationUtils\n    from marimo._messaging.tracebacks import write_traceback\n    from marimo._output import formatting\n\n    output = formatting.try_format(value)\n    if output.traceback is not None:\n        write_traceback(output.traceback)\n    CellNotificationUtils.broadcast_output(\n        channel=CellChannel.OUTPUT,\n        mimetype=output.mimetype,\n        data=output.data,\n        cell_id=cell_id,  # type: ignore[arg-type]\n        status=None,\n    )\n\n\ndef _mo_create_replace() -> Callable[[object], None] | None:\n    """Create mo.output.replace with current cell context pinned."""\n    from marimo._output import formatting\n    from marimo._runtime.context import get_context\n    from marimo._runtime.context.types import ContextNotInitializedError\n\n    try:\n        ctx = get_context()\n    except ContextNotInitializedError:\n        return None\n\n    if ctx.execution_context is None:\n        return None\n\n    cell_id = ctx.execution_context.cell_id\n    execution_context = ctx.execution_context\n\n    def replace(value: object) -> None:\n        execution_context.output = [formatting.as_html(value)]\n        _mo_write_internal(cell_id=cell_id, value=value)\n\n    return replace\n\n\nclass MarimoProgressBackend:\n    """Marimo-based progress bar backend for HTML rendering.\n\n    This backend renders progress bars as HTML tables in marimo notebooks,\n    providing a rich visual display with automatic updates.\n    """\n\n    def __init__(\n        self,\n        step_name: str,\n        n_bars: int,\n        total: int | float,\n        combined: bool,\n        full_stats: bool,\n        css_theme: str | None = None,\n    ):\n        self.step_name = step_name\n        self.n_bars = n_bars\n        self.total = total\n        self.combined = combined\n        self.full_stats = full_stats\n        self._css_theme = DEFAULT_CSS if css_theme is None else css_theme\n\n        self._mo_replace: Callable[[object], None] | None = None\n        self._task_state: list[dict[str, Any]] = []\n        self._start_times: list[float] = []\n\n    @property\n    def is_enabled(self) -> bool:\n        """Whether the progress bar is enabled (always True for marimo backend)."""\n        return True\n\n    def __enter__(self):\n        """Enter the context manager and initialize display."""\n        import marimo as mo\n\n        self._mo_replace = _mo_create_replace()\n        self._initialize_tasks()\n        mo.output.clear()\n        self._render()\n\n    def __exit__(self, exc_type, exc_val, exc_tb) -> None:\n        """Exit the context manager with final render."""\n        self._render()\n\n    def _initialize_tasks(self) -> None:\n        """Initialize progress tracking state for all tasks."""\n        if self.combined:\n            self._task_state = [\n                {\n                    "completed": 0,\n                    "total": self.total * self.n_bars,\n                    "failing": False,\n                    "stats": {},\n                }\n            ]\n            self._start_times = [perf_counter()]\n        else:\n            self._task_state = [\n                {\n                    "completed": 0,\n                    "total": self.total,\n                    "failing": False,\n                    "stats": {},\n                }\n                for _ in range(self.n_bars)\n            ]\n            self._start_times = [perf_counter() for _ in range(self.n_bars)]\n\n    def update(\n        self,\n        task_id: int,\n        advance: int | float,\n        failing: bool,\n        stats: dict[str, Any],\n        is_last: bool,\n    ) -> None:\n        """Update progress for a specific task.\n\n        Parameters\n        ----------\n        task_id : int\n            Index of the progress bar being updated\n        advance : int or float\n            Amount to advance the progress bar by\n        failing : bool\n            Whether the task has encountered failures\n        stats : dict\n            Statistics to display\n        is_last : bool\n            Whether this is the final update\n        """\n        self._task_state[task_id]["completed"] += advance\n        self._task_state[task_id]["failing"] = failing\n        self._task_state[task_id]["stats"] = stats\n\n        if is_last:\n            # Ensure bar is fully filled on completion\n            total = self._task_state[task_id]["total"]\n            completed = self._task_state[task_id]["completed"]\n            remaining = total - completed\n            if remaining > 0:\n                self._task_state[task_id]["completed"] = total\n\n        self._render()\n\n    def _render(self) -> None:\n        """Render HTML progress display to marimo output."""\n        if self._mo_replace is None:\n            return\n\n        import marimo as mo\n\n        html = self._render_html()\n        self._mo_replace(mo.Html(html))\n\n    def _render_html(self) -> str:\n        """Generate HTML for all progress bars as a table with headers."""\n        stat_keys = []\n        if self.full_stats and self._task_state and self._task_state[0]["stats"]:\n            stat_keys = list(self._task_state[0]["stats"].keys())\n\n        header_cells = ["Progress", self.step_name]\n\n        abbreviations = {\n            "divergences": "Div",\n            "diverging": "Div",\n            "step_size": "Step",\n            "tree_size": "Tree",\n            "tree_depth": "Depth",\n            "n_steps": "Steps",\n            "energy_error": "E-err",\n            "max_energy_error": "Max-E",\n            "mean_tree_accept": "Accept",\n            "scaling": "Scale",\n            "tune": "Tune",\n        }\n        header_cells += [abbreviations.get(k, k[:6].capitalize()) for k in stat_keys]\n\n        header_cells += ["Speed", "Elapsed"]\n\n        header_row = "<tr>" + "".join(f"<th>{h}</th>" for h in header_cells) + "</tr>"\n\n        data_rows = []\n        for i, state in enumerate(self._task_state):\n            data_rows.append(self._render_task_row(i, state, stat_keys))\n\n        rows_html = "\\n".join(data_rows)\n        return f"""\n            <style>{self._css_theme}</style>\n            <table class=\'pymc-progress-table\'>\n                <thead>{header_row}</thead>\n                <tbody>{rows_html}</tbody>\n            </table>\n        """\n\n    def _render_task_row(self, task_id: int, state: dict[str, Any], stat_keys: list[str]) -> str:\n        """Render a single task\'s progress as a table row."""\n        completed = state["completed"]\n        total = state["total"]\n        failing = state["failing"]\n        stats = state["stats"]\n\n        pct = (completed / total * 100) if total > 0 else 0\n        elapsed = perf_counter() - self._start_times[task_id]\n\n        action = self.step_name.lower()\n        speed = completed / max(elapsed, 1e-6)\n        if speed > 1 or speed == 0:\n            unit = f"{action}s/s"\n        else:\n            unit = f"s/{action}"\n            speed = 1 / speed\n\n        bar_class = "pymc-progress-bar"\n        if failing:\n            bar_class += " failing"\n        elif pct >= 100:\n            bar_class += " finished"\n\n        cells = [\n            f\'<td><div class="pymc-progress-bar-container"><div class="{bar_class}" style="width: {pct:.1f}%"></div></div></td>\',\n            f"<td>{completed}/{total} ({pct:.0f}%)</td>",\n        ]\n\n        for key in stat_keys:\n            val = stats.get(key, "")\n            if isinstance(val, float):\n                cells.append(f"<td>{val:.3f}</td>")\n            else:\n                cells.append(f"<td>{val}</td>")\n\n        cells.append(f"<td>{speed:.1f} {unit}</td>")\n        cells.append(f"<td>{format_time(elapsed)}</td>")\n\n        return "<tr>" + "".join(cells) + "</tr>"\n\n\nclass MarimoSimpleProgress:\n    """Simple marimo-aware progress bar for forward sampling functions.\n\n    This provides a similar interface to CustomProgress but renders using\n    HTML in marimo notebooks for better display.\n    """\n\n    def __init__(self, theme: str | None = None):\n        self.description = ""\n        self.total = 0\n        self.completed = 0\n        self._css_theme = DEFAULT_CSS if theme is None else theme\n\n        self._mo_replace: Callable[[object], None] | None = None\n        self._start_time: float = 0.0\n        self._task_id = 0\n\n    def __enter__(self) -> Self:\n        """Enter the context manager."""\n        self._mo_replace = _mo_create_replace()\n        self._start_time = perf_counter()\n\n        import marimo as mo\n\n        mo.output.clear()\n        self._render()\n        return self\n\n    def __exit__(self, exc_type, exc_val, exc_tb) -> None:\n        """Exit the context manager with final render."""\n        self._render()\n\n    def add_task(\n        self, description: str, completed: int = 0, total: int | None = None, **kwargs\n    ) -> int:\n        """Add a task (interface compatibility with CustomProgress).\n\n        Kwargs are ignored since MarimoSimpleProgress\n        only supports a single task initialized at construction.\n        """\n        self.description = description\n        self.completed = completed\n        if total is not None:\n            self.total = total\n        self._render()\n        return self._task_id\n\n    def advance(self, task_id: int | None = None, advance: int = 1) -> None:\n        """Advance the progress bar.\n\n        Parameters\n        ----------\n        task_id : int, optional\n            Ignored (for interface compatibility)\n        advance : int\n            Amount to advance by\n        """\n        self.completed += advance\n        self._render()\n\n    def update(\n        self,\n        task_id: int | None = None,\n        refresh: bool = False,\n        completed: int | None = None,\n        **kwargs,\n    ) -> None:\n        """Update the progress bar state.\n\n        Parameters\n        ----------\n        task_id : int, optional\n            Ignored (for interface compatibility)\n        refresh : bool\n            If True, force a render\n        completed : int, optional\n            Set completed count\n        **kwargs\n            Additional arguments ignored for compatibility\n        """\n        if completed is not None:\n            self.completed = completed\n        if refresh:\n            self._render()\n\n    def _render(self) -> None:\n        """Render HTML progress to marimo output."""\n        if self._mo_replace is None:\n            return\n\n        import marimo as mo\n\n        html = self._render_html()\n        self._mo_replace(mo.Html(html))\n\n    def _render_html(self) -> str:\n        """Generate HTML for the progress bar as a table."""\n        pct = (self.completed / self.total * 100) if self.total > 0 else 0\n        elapsed = perf_counter() - self._start_time\n\n        if elapsed > 0 and self.completed > 0:\n            speed = self.completed / elapsed\n            if speed > 1:\n                speed_str = f"{speed:.1f} samples/s"\n            else:\n                speed_str = f"{1 / speed:.1f} s/sample"\n        else:\n            speed_str = "-- samples/s"\n\n        if self.completed > 0 and self.completed < self.total:\n            remaining = (self.total - self.completed) / (self.completed / elapsed)\n            remaining_str = format_time(remaining)\n        else:\n            remaining_str = "--:--"\n\n        elapsed_str = format_time(elapsed)\n\n        bar_class = "pymc-progress-bar"\n        if pct >= 100:\n            bar_class += " finished"\n\n        return f"""<style>{self._css_theme}</style>\n<table class="pymc-progress-table">\n<thead><tr><th>Progress</th><th>Samples</th><th>Speed</th><th>Elapsed</th><th>Remaining</th></tr></thead>\n<tbody><tr>\n<td><div class="pymc-progress-bar-container"><div class="{bar_class}" style="width: {pct:.1f}%"></div></div></td>\n<td>{self.completed}/{self.total} ({pct:.0f}%)</td>\n<td>{speed_str}</td>\n<td>{elapsed_str}</td>\n<td>{remaining_str}</td>\n</tr></tbody>\n</table>"""\n',
            'pymc/progress_bar/progress.py': '#   Copyright 2025 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nfrom __future__ import annotations\n\nfrom abc import ABC, abstractmethod\nfrom contextlib import nullcontext\nfrom typing import TYPE_CHECKING, Any, Literal, Protocol, Self\n\nfrom rich.theme import Theme\n\nfrom pymc.progress_bar.marimo_progress import (\n    MarimoProgressBackend,\n    MarimoSimpleProgress,\n    in_marimo_notebook,\n)\nfrom pymc.progress_bar.rich_progress import (\n    RichProgressBackend,\n    RichSimpleProgress,\n)\n\nif TYPE_CHECKING:\n    from pymc.smc.kernels import SMC_KERNEL\n    from pymc.step_methods.compound import BlockedStep, CompoundStep\n\n\nProgressBarOptions = Literal[\n    "combined",\n    "split",\n    "combined+stats",\n    "stats+combined",\n    "split+stats",\n    "stats+split",\n]\n\n\nclass ProgressBackend(Protocol):\n    """Protocol defining the interface for progress bar rendering backends.\n\n    Any backend that implements this protocol can be used with ProgressBarManager.\n    """\n\n    def __enter__(self) -> Self: ...\n\n    def __exit__(\n        self, exc_type: type[BaseException] | None, exc_val: BaseException | None, exc_tb: Any\n    ) -> None: ...\n\n    def update(\n        self,\n        task_id: int,\n        advance: int | float,\n        failing: bool,\n        stats: dict[str, Any],\n        is_last: bool,\n    ) -> None: ...\n\n\nclass NullProgressBackend(nullcontext):\n    def update(self, *args, **kwargs): ...\n\n\nclass ProgressBarManager(ABC):\n    """Abstract base class for progress bar managers.\n\n    This class handles the common logic for progress bar management including:\n    - Environment detection (terminal vs marimo notebook)\n    - Backend selection and initialization\n    - Configuration parsing\n\n    Subclasses implement sampling-specific logic like how to track progress\n    and how to extract statistics from step methods.\n    """\n\n    _backend: ProgressBackend\n    _show_progress: bool\n    combined_progress: bool\n    full_stats: bool\n    n_bars: int\n    step_name: str = "Completed"\n\n    def __init__(\n        self,\n        n_bars: int,\n        progressbar: bool | ProgressBarOptions = True,\n        progressbar_theme: Theme | str | None = None,\n    ):\n        """Initialize the progress bar manager.\n\n        Parameters\n        ----------\n        n_bars : int\n            Number of progress bars to draw\n        progressbar : bool or ProgressBarOptions\n            Progress bar display mode\n        progressbar_theme : Theme or str, optional\n            Rich theme for terminal progress bars, or CSS string for marimo\n        """\n        self.n_bars = n_bars\n        self._progressbar_theme = progressbar_theme\n\n        match progressbar:\n            case True:\n                self.combined_progress = False\n                self.full_stats = True\n                show_progress = True\n            case False:\n                self.combined_progress = False\n                self.full_stats = True\n                show_progress = False\n            case "combined":\n                self.combined_progress = True\n                self.full_stats = False\n                show_progress = True\n            case "split":\n                self.combined_progress = False\n                self.full_stats = False\n                show_progress = True\n            case "combined+stats" | "stats+combined":\n                self.combined_progress = True\n                self.full_stats = True\n                show_progress = True\n            case "split+stats" | "stats+split":\n                self.combined_progress = False\n                self.full_stats = True\n                show_progress = True\n            case _:\n                raise ValueError(\n                    "Invalid value for `progressbar`. Valid values are True (default), "\n                    "False (no progress bar), one of \'combined\', \'split\', \'split+stats\', "\n                    "or \'combined+stats\'."\n                )\n\n        self._show_progress = show_progress\n\n    def _create_backend(\n        self,\n        total: int | float,\n        progress_columns: list,\n        progress_stats: dict[str, list[Any]],\n    ) -> ProgressBackend:\n        """Create the appropriate backend based on environment.\n\n        Parameters\n        ----------\n        total : int\n            Total number of progress units (draws, etc.)\n        progress_columns : list\n            Column definitions for the progress bar\n        progress_stats : dict\n            Initial statistics values by chain\n\n        Returns\n        -------\n        ProgressBackend\n            The appropriate backend for the current environment\n        """\n        if not self._show_progress:\n            return NullProgressBackend()\n        elif in_marimo_notebook():\n            return MarimoProgressBackend(\n                step_name=self.step_name,\n                n_bars=1 if self.combined_progress else self.n_bars,\n                total=total,\n                combined=self.combined_progress,\n                full_stats=self.full_stats,\n                css_theme=self._progressbar_theme\n                if isinstance(self._progressbar_theme, str)\n                else None,\n            )\n        else:\n            return RichProgressBackend(\n                step_name=self.step_name,\n                n_bars=1 if self.combined_progress else self.n_bars,\n                total=total,\n                combined=self.combined_progress,\n                full_stats=self.full_stats,\n                progress_columns=progress_columns,\n                progress_stats=progress_stats,\n                theme=self._progressbar_theme\n                if isinstance(self._progressbar_theme, Theme)\n                else None,\n            )\n\n    def __enter__(self) -> Self:\n        self._backend.__enter__()\n        return self\n\n    def __exit__(self, exc_type, exc_val, exc_tb):\n        return self._backend.__exit__(exc_type, exc_val, exc_tb)\n\n    @abstractmethod\n    def update(self, *args, **kwargs) -> None:\n        """Update progress bar with new sampling statistics.\n\n        Subclasses must implement this with their specific signature.\n        """\n        ...\n\n\nclass MCMCProgressBarManager(ProgressBarManager):\n    """Progress bar manager for MCMC sampling.\n\n    Tracks progress via draw count with support for tuning phases.\n    """\n\n    step_name: str = "Draws"\n\n    def __init__(\n        self,\n        step_method: BlockedStep | CompoundStep,\n        chains: int,\n        draws: int,\n        tune: int,\n        progressbar: bool | ProgressBarOptions = True,\n        progressbar_theme: Theme | str | None = None,\n    ):\n        """Initialize the MCMC progress bar manager.\n\n        Parameters\n        ----------\n        step_method : BlockedStep or CompoundStep\n            The step method being used for sampling\n        chains : int\n            Number of chains being sampled\n        draws : int\n            Number of draws per chain\n        tune : int\n            Number of tuning steps per chain\n        progressbar : bool or ProgressBarOptions\n            Progress bar display mode\n        progressbar_theme : Theme or str, optional\n            Rich theme for terminal progress bars, or CSS string for marimo\n        """\n        super().__init__(\n            n_bars=chains,\n            progressbar=progressbar,\n            progressbar_theme=progressbar_theme,\n        )\n\n        progress_columns, progress_stats = step_method._progressbar_config(chains)\n        progress_stats["draws"] = [0] * chains\n\n        self.progress_stats = progress_stats\n        self.update_stats_functions = step_method._make_progressbar_update_functions()\n\n        self.completed_draws = 0\n        self.total_draws = draws + tune\n\n        self._backend = self._create_backend(\n            total=self.total_draws * chains if self.combined_progress else self.total_draws,\n            progress_columns=progress_columns,\n            progress_stats=progress_stats,\n        )\n\n    @property\n    def chains(self) -> int:\n        """Number of chains being sampled."""\n        return self.n_bars\n\n    def _extract_stats(self, stats) -> tuple[bool, dict[str, Any]]:\n        """Extract and process stats from step methods."""\n        failing = False\n        all_step_stats: dict[str, Any] = {}\n\n        chain_progress_stats = [\n            update_stats_fn(step_stats)\n            for update_stats_fn, step_stats in zip(self.update_stats_functions, stats, strict=True)\n        ]\n        for step_stats in chain_progress_stats:\n            for key, val in step_stats.items():\n                if key == "failing":\n                    failing |= val\n                    continue\n                if not self.full_stats:\n                    continue\n                if key in all_step_stats:\n                    continue\n                else:\n                    all_step_stats[key] = val\n\n        return failing, all_step_stats\n\n    def update(self, chain_idx: int, is_last: bool, draw: int, tuning: bool, stats) -> None:\n        """Update progress bar with new sampling statistics.\n\n        Parameters\n        ----------\n        chain_idx : int\n            Index of the chain being updated\n        is_last : bool\n            Whether this is the final update\n        draw : int\n            Current draw number\n        tuning : bool\n            Whether the chain is in tuning phase\n        stats : list\n            Statistics from each step method\n        """\n        if not self._show_progress:\n            return\n\n        self.completed_draws += 1\n        if self.combined_progress:\n            draw = self.completed_draws\n            chain_idx = 0\n\n        failing, all_step_stats = self._extract_stats(stats)\n        all_step_stats["draws"] = draw\n\n        self._backend.update(\n            task_id=chain_idx,\n            advance=1,\n            failing=failing,\n            stats=all_step_stats,\n            is_last=is_last,\n        )\n\n\nclass SMCProgressBarManager(ProgressBarManager):\n    """Progress bar manager for SMC sampling.\n\n    Unlike MCMC which tracks a fixed number of draws, SMC tracks progress\n    via the beta parameter (inverse temperature) which goes from 0 to 1.\n    """\n\n    step_name: str = "Stage"\n\n    def __init__(\n        self,\n        kernel: SMC_KERNEL,\n        chains: int,\n        progressbar: bool = True,\n        progressbar_theme: Theme | str | None = None,\n    ):\n        """Initialize the SMC progress bar manager.\n\n        Parameters\n        ----------\n        kernel : SMC_KERNEL\n            The SMC kernel being used\n        chains : int\n            Number of processes being run.\n        progressbar : bool\n            Whether to display the progress bar\n        progressbar_theme : Theme or str, optional\n            Rich theme for terminal progress bars, or CSS string for marimo\n        """\n        # SMC doesn\'t use combined/split modes - each chain runs independently\n        # and beta goes from 0 to 1, so we force split mode with full stats\n        super().__init__(\n            n_bars=chains,\n            progressbar=progressbar,\n            progressbar_theme=progressbar_theme,\n        )\n        # Override base class settings for SMC-specific behavior\n        self.combined_progress = False\n        self.full_stats = True\n\n        progress_columns, progress_stats = kernel._progressbar_config(chains)\n        progress_stats["stage"] = [0] * chains\n\n        self.progress_stats = progress_stats\n        self.update_stats_functions = kernel._make_progressbar_update_functions()\n\n        self._backend = self._create_backend(\n            total=1.0,\n            progress_columns=progress_columns,\n            progress_stats=progress_stats,\n        )\n\n    @property\n    def chains(self):\n        return self.n_bars\n\n    def update(\n        self,\n        chain_idx: int,\n        stage: int,\n        beta: float,\n        old_beta: float | None = None,\n        is_last: bool = False,\n    ) -> None:\n        """Update a progress bar.\n\n        Parameters\n        ----------\n        chain_idx : int\n            Index of the chain being updated\n        stage : int\n            Current stage number\n        beta : float\n            Current beta value (0 to 1)\n        old_beta : float, optional\n            Previous beta value, used to compute advancement\n        is_last : bool\n            Whether this is the last update for this chain\n        """\n        if not self._show_progress:\n            return\n\n        stats = [{"beta": beta}]\n        all_step_stats: dict[str, Any] = {}\n\n        chain_progress_stats = [\n            update_stats_fn(step_stats)\n            for update_stats_fn, step_stats in zip(self.update_stats_functions, stats, strict=True)\n        ]\n\n        for step_stats in chain_progress_stats:\n            for key, val in step_stats.items():\n                all_step_stats[key] = val\n\n        all_step_stats["stage"] = stage\n\n        advance = beta - (old_beta if old_beta is not None else 0.0)\n\n        self._backend.update(\n            task_id=chain_idx,\n            advance=advance,\n            failing=False,\n            stats=all_step_stats,\n            is_last=is_last,\n        )\n\n\nclass SimpleProgressBackend(Protocol):\n    def __enter__(self) -> Self: ...\n\n    def __exit__(\n        self, exc_type: type[BaseException] | None, exc_val: BaseException | None, exc_tb: Any\n    ) -> None: ...\n\n    def add_task(self, description: str, completed: int, total: int) -> int: ...\n\n    def advance(self, task_id: int | None, advance: int = 1) -> None: ...\n\n    def update(self, task_id: int, refresh: bool, completed: int) -> None: ...\n\n\nclass NullSimpleProgress(nullcontext):\n    def add_task(self, *args, **kwargs) -> int:\n        return 0\n\n    def advance(self, *args, **kwargs) -> None:\n        return\n\n    def update(self, *args, **kwargs) -> None:\n        return\n\n\ndef create_simple_progress(\n    progressbar: bool = True,\n    progressbar_theme: Theme | str | None = None,\n) -> SimpleProgressBackend:\n    """Create a simple progress bar appropriate for the current environment."""\n    if not progressbar:\n        return NullSimpleProgress()\n\n    elif in_marimo_notebook():\n        return MarimoSimpleProgress(\n            theme=progressbar_theme if isinstance(progressbar_theme, str) else None\n        )\n\n    else:\n        return RichSimpleProgress(\n            theme=progressbar_theme if isinstance(progressbar_theme, Theme) else None\n        )\n',
            'pymc/progress_bar/rich_progress.py': '#   Copyright 2025 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nfrom collections.abc import Iterable\nfrom sys import stderr\nfrom typing import Any, Self\n\nfrom rich.box import SIMPLE_HEAD\nfrom rich.console import Console\nfrom rich.progress import (\n    BarColumn,\n    Progress,\n    ProgressColumn,\n    Task,\n    TaskID,\n    TextColumn,\n    TimeElapsedColumn,\n    TimeRemainingColumn,\n)\nfrom rich.style import Style\nfrom rich.table import Column, Table\nfrom rich.theme import Theme\n\ndefault_progress_theme = Theme(\n    {\n        "bar.complete": "#1764f4",\n        "bar.finished": "#1764f4",\n        "progress.remaining": "none",\n        "progress.elapsed": "none",\n    }\n)\n\n\nclass CustomProgress(Progress):\n    def __init__(self, *args, include_headers: bool = False, **kwargs):\n        self.include_headers = include_headers\n        super().__init__(*args, **kwargs)\n\n    def make_tasks_table(self, tasks: Iterable[Task]) -> Table:\n        """Get a table to render the Progress display.\n\n        Unlike the parent method, this returns a full table (not a grid),\n        allowing for column headings.\n\n        Parameters\n        ----------\n        tasks : Iterable[Task]\n            An iterable of Task instances, one per row of the table.\n\n        Returns\n        -------\n        Table\n            A table instance.\n        """\n\n        def call_column(column, task):\n            if hasattr(column, "callbacks"):\n                column.callbacks(task)\n            return column(task)\n\n        table_columns = (\n            (\n                Column(no_wrap=True)\n                if isinstance(_column, str)\n                else _column.get_table_column().copy()\n            )\n            for _column in self.columns\n        )\n        if self.include_headers:\n            table = Table(\n                *table_columns,\n                padding=(0, 1),\n                expand=self.expand,\n                show_header=True,\n                show_edge=True,\n                box=SIMPLE_HEAD,\n            )\n        else:\n            table = Table.grid(*table_columns, padding=(0, 1), expand=self.expand)\n\n        for task in tasks:\n            if task.visible:\n                table.add_row(\n                    *(\n                        (\n                            column.format(task=task)\n                            if isinstance(column, str)\n                            else call_column(column, task)\n                        )\n                        for column in self.columns\n                    )\n                )\n\n        return table\n\n\nclass RecolorOnFailureBarColumn(BarColumn):\n    """Rich colorbar that changes color when a chain has detected a failure."""\n\n    def __init__(self, *args, failing_color: str = "red", **kwargs):\n        from matplotlib.colors import to_rgb\n\n        self.failing_color = failing_color\n        self.failing_rgb = [int(x * 255) for x in to_rgb(self.failing_color)]\n\n        super().__init__(*args, **kwargs)\n\n        self.default_complete_style = self.complete_style\n        self.default_finished_style = self.finished_style\n\n    def callbacks(self, task: Task):\n        """Update bar color based on failure state."""\n        if task.fields["failing"]:\n            self.complete_style = Style.parse("rgb({},{},{})".format(*self.failing_rgb))\n            self.finished_style = Style.parse("rgb({},{},{})".format(*self.failing_rgb))\n        else:\n            self.complete_style = self.default_complete_style\n            self.finished_style = self.default_finished_style\n\n\nclass RichProgressBackend:\n    """Rich-based progress bar backend for terminal rendering.\n\n    This backend uses the Rich library to render progress bars in terminals\n    and Jupyter notebooks.\n    """\n\n    def __init__(\n        self,\n        step_name: str,\n        n_bars: int,\n        total: int | float,\n        combined: bool,\n        full_stats: bool,\n        progress_columns: list,\n        progress_stats: dict[str, list[Any]],\n        theme: Theme | None = None,\n    ):\n        """Initialize the Rich progress backend.\n\n        Parameters\n        ----------\n        step_name : str\n            Name of the unit of iteration (e.g., "draws", "particles")\n        n_bars : int\n            Number of progress bars to display\n        total : int\n            Total number of iterations per bar\n        combined : bool\n            Whether to show a single combined progress bar\n        full_stats : bool\n            Whether to show detailed statistics\n        progress_columns : list\n            Rich column definitions from step method\n        progress_stats : dict\n            Initial values for statistics by task\n        theme : Theme, optional\n            Rich theme for styling\n        """\n        self.step_name = step_name\n        self.n_bars = n_bars\n        self.total = total\n        self.combined = combined\n        self.full_stats = full_stats\n        self.progress_stats = progress_stats\n\n        self._progress = self._create_progress_bar(\n            progress_columns=progress_columns,\n            theme=default_progress_theme if theme is None else theme,\n        )\n        self._tasks: list[TaskID | None] = []\n\n    def _create_progress_bar(\n        self,\n        progress_columns: list,\n        theme: Theme,\n    ) -> CustomProgress:\n        columns: list[ProgressColumn] = [\n            TextColumn(\n                "{" + f"task.fields[{self.step_name.lower()}]" + "}",\n                table_column=Column(self.step_name.title(), ratio=1),\n            )\n        ]\n\n        if self.full_stats:\n            columns += progress_columns\n\n        columns += [\n            TextColumn(\n                "{task.fields[sampling_speed]:0.2f} {task.fields[speed_unit]}",\n                table_column=Column("Sampling Speed", ratio=1),\n            ),\n            TimeElapsedColumn(table_column=Column("Elapsed", ratio=1)),\n            TimeRemainingColumn(table_column=Column("Remaining", ratio=1)),\n        ]\n\n        return CustomProgress(\n            RecolorOnFailureBarColumn(\n                table_column=Column("Progress", ratio=2),\n                failing_color="tab:red",\n                complete_style=Style.parse("rgb(31,119,180)"),\n                finished_style=Style.parse("rgb(31,119,180)"),\n            ),\n            *columns,\n            console=Console(file=stderr, theme=theme),\n            include_headers=True,\n        )\n\n    def __enter__(self) -> Self:\n        self._progress.__enter__()\n        self._initialize_tasks()\n        return self\n\n    def __exit__(self, exc_type, exc_val, exc_tb) -> None:\n        self._progress.__exit__(exc_type, exc_val, exc_tb)\n\n    def _initialize_tasks(self) -> None:\n        if self.combined:\n            self._tasks = [\n                self._progress.add_task(\n                    "Sampling",\n                    completed=0,\n                    total=self.total * self.n_bars - 1,\n                    task_idx=0,\n                    sampling_speed=0,\n                    speed_unit="draws/s",\n                    failing=False,\n                    **{stat: value[0] for stat, value in self.progress_stats.items()},\n                )\n            ]\n        else:\n            self._tasks = [\n                self._progress.add_task(\n                    "Sampling",\n                    completed=0,\n                    total=self.total - 1,\n                    task_idx=task_idx,\n                    sampling_speed=0,\n                    speed_unit="draws/s",\n                    failing=False,\n                    **{stat: value[task_idx] for stat, value in self.progress_stats.items()},\n                )\n                for task_idx in range(self.n_bars)\n            ]\n\n    def update(\n        self,\n        task_id: int,\n        advance: int | float,\n        failing: bool,\n        stats: dict[str, Any],\n        is_last: bool,\n    ) -> None:\n        """Update a progress bar.\n\n        Parameters\n        ----------\n        task_id : int\n            Index of the progress bar being updated\n        advance : int or float\n            Amount to advance the progress bar by\n        failing : bool\n            Whether the process has encountered failures\n        stats : dict\n            Statistics to display\n        is_last : bool\n            Whether this is the final update\n        """\n        rich_task_id = self._tasks[task_id]\n        if rich_task_id is None:\n            return\n\n        self._progress.advance(rich_task_id, advance=advance)\n\n        task = self._progress.tasks[task_id]\n        completed = task.completed\n        elapsed = task.elapsed if task.elapsed is not None else 0.0\n\n        action = self.step_name.lower()\n        speed = completed / max(elapsed, 1e-6)\n        if speed > 1 or speed == 0:\n            unit = f"{action}s/s"\n        else:\n            unit = f"s/{action}"\n            speed = 1 / speed\n\n        self._progress.update(\n            rich_task_id,\n            sampling_speed=speed,\n            speed_unit=unit,\n            failing=failing,\n            **stats,\n        )\n\n        if is_last:\n            # Ensure bar is fully filled on completion\n            remaining = task.total - task.completed if task.total else 0\n            if remaining > 0:\n                self._progress.advance(rich_task_id, advance=remaining)\n            self._progress.update(\n                rich_task_id,\n                failing=failing,\n                **stats,\n                refresh=True,\n            )\n\n\ndef RichSimpleProgress(theme: Theme | None):\n    return CustomProgress(\n        "[progress.description]{task.description}",\n        BarColumn(),\n        "[progress.percentage]{task.percentage:>3.0f}%",\n        TimeRemainingColumn(),\n        TextColumn("/"),\n        TimeElapsedColumn(),\n        console=Console(file=stderr, theme=default_progress_theme if theme is None else theme),\n    )\n',
            'pymc/smc/parallel.py': '#   Copyright 2026 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport logging\nimport multiprocessing\nimport time\n\nfrom collections import namedtuple\nfrom collections.abc import Sequence\nfrom contextlib import nullcontext\n\nimport cloudpickle\nimport numpy as np\n\nfrom rich.theme import Theme\nfrom threadpoolctl import threadpool_limits\n\nfrom pymc.progress_bar import SMCProgressBarManager, default_progress_theme\nfrom pymc.sampling.parallel import ExceptionWithTraceback, ParallelSamplingError\nfrom pymc.smc.kernels import SMC_KERNEL\nfrom pymc.util import RandomGeneratorState, get_state_from_generator, random_generator_from_state\n\nlogger = logging.getLogger(__name__)\n\nSMCResult = namedtuple(\n    "SMCResult",\n    [\n        "chain",\n        "is_last",\n        "stage",\n        "beta",\n        "tempered_posterior",\n        "var_info",\n        "variables",\n        "sample_stats",\n        "sample_settings",\n    ],\n)\n\n\nclass _SMCProcess:\n    """Separate process for each SMC chain.\n\n    Follows the pattern from parallel.py but adapted for SMC sampling.\n    """\n\n    def __init__(\n        self,\n        name: str,\n        msg_pipe,\n        kernel,\n        start,\n        rng_state: RandomGeneratorState,\n        chain: int,\n        mp_start_method: str,\n        blas_cores: int | None,\n    ):\n        self._msg_pipe = msg_pipe\n        self._kernel = kernel\n        self._start = start\n        self._rng = random_generator_from_state(rng_state)\n        self.chain = chain\n        self._mp_start_method = mp_start_method\n        self._blas_cores = blas_cores\n\n    def _unpickle_objects(self):\n        """Unpickle kernel and start point."""\n        self._kernel = cloudpickle.loads(self._kernel)\n        if self._start is not None:\n            self._start = cloudpickle.loads(self._start)\n\n    def run(self):\n        with (\n            nullcontext()\n            if self._mp_start_method == "fork"\n            else threadpool_limits(limits=self._blas_cores)\n        ):\n            self._unpickle_objects()\n\n            try:\n                self._run_smc()\n            except KeyboardInterrupt:\n                pass\n            except BaseException as e:\n                e = ExceptionWithTraceback(e, e.__traceback__)\n                self._msg_pipe.send(("error", e))\n                self._wait_for_abortion()\n            finally:\n                self._msg_pipe.close()\n\n    def _wait_for_abortion(self):\n        """Wait for abort message from main process."""\n        while True:\n            msg = self._recv_msg()\n            if msg[0] == "abort":\n                break\n\n    def _recv_msg(self):\n        """Receive message from main process."""\n        return self._msg_pipe.recv()\n\n    def _run_smc(self):\n        """Run the SMC sampling algorithm."""\n        msg = self._recv_msg()\n        if msg[0] == "abort":\n            raise KeyboardInterrupt()\n        if msg[0] != "start":\n            raise ValueError("Unexpected msg " + msg[0])\n\n        smc = self._kernel\n        smc.initialize(self._start, self._rng)\n\n        stage = 0\n        sample_stats: dict[str, list] = {stat: [] for stat in smc.stats_dtypes_shapes}  # type: ignore[annotation-unchecked]\n\n        while smc.beta < 1:\n            smc.update_beta_and_weights()\n\n            self._msg_pipe.send(("progress", stage, smc.beta))\n\n            msg = self._recv_msg()\n            if msg[0] == "abort":\n                raise KeyboardInterrupt()\n            elif msg[0] != "continue":\n                raise ValueError("Unknown message " + msg[0])\n\n            for stat, value in smc.step().items():\n                sample_stats[stat].append(value)\n\n            stage += 1\n\n        result = cloudpickle.dumps(\n            (\n                stage,\n                smc.beta,\n                smc.tempered_posterior,\n                smc.var_info,\n                smc.variables,\n                sample_stats,\n                smc.sample_settings(),\n            ),\n            protocol=-1,\n        )\n        self._msg_pipe.send(("done", result))\n\n\ndef _run_smc_process(*args):\n    """Entry point for SMC process."""\n    _SMCProcess(*args).run()\n\n\nclass SMCProcessAdapter:\n    """Adapter to control an SMC process from the main thread."""\n\n    def __init__(\n        self,\n        kernel,\n        chain: int,\n        rng: np.random.Generator,\n        start,\n        mp_ctx,\n        blas_cores: int | None,\n    ):\n        self.chain = chain\n        process_name = f"smc_worker_chain_{chain}"\n        self._msg_pipe, remote_conn = multiprocessing.Pipe()\n\n        self._process = mp_ctx.Process(\n            daemon=True,\n            name=process_name,\n            target=_run_smc_process,\n            args=(\n                process_name,\n                remote_conn,\n                kernel,\n                start,\n                get_state_from_generator(rng),\n                chain,\n                mp_ctx.get_start_method(),\n                blas_cores,\n            ),\n        )\n        self._process.start()\n        remote_conn.close()\n\n        self._current_stage = 0\n        self._current_beta = 0.0\n\n    def _send(self, msg, *args):\n        """Send message to the worker process."""\n        try:\n            self._msg_pipe.send((msg, *args))\n        except Exception:\n            message = None\n            try:\n                message = self._msg_pipe.recv()\n            except Exception:\n                pass\n            if message is not None and message[0] == "error":\n                old_error = message[1]\n                if old_error is not None:\n                    error = ParallelSamplingError(\n                        f"Chain {self.chain} failed with: {old_error}", self.chain\n                    )\n                else:\n                    error = RuntimeError(f"Chain {self.chain} failed.")\n                raise error from old_error\n            raise\n\n    def start(self):\n        """Send start signal to the worker."""\n        self._send("start")\n\n    def continue_sampling(self):\n        """Send continue signal to the worker."""\n        self._send("continue")\n\n    def abort(self):\n        """Send abort signal to the worker."""\n        self._send("abort")\n\n    def join(self, timeout=None):\n        """Join the worker process."""\n        self._process.join(timeout)\n\n    def terminate(self):\n        """Terminate the worker process."""\n        self._process.terminate()\n\n    @staticmethod\n    def recv_message(processes, timeout=3600):\n        """Receive a message from any of the worker processes."""\n        if not processes:\n            raise ValueError("No processes.")\n        pipes = [proc._msg_pipe for proc in processes]\n        ready = multiprocessing.connection.wait(pipes, timeout=timeout)\n        if not ready:\n            raise multiprocessing.TimeoutError("No message from samplers.")\n        idxs = {id(proc._msg_pipe): proc for proc in processes}\n        proc = idxs[id(ready[0])]\n        msg = ready[0].recv()\n\n        if msg[0] == "error":\n            old_error = msg[1]\n            if old_error is not None:\n                error = ParallelSamplingError(\n                    f"Chain {proc.chain} failed with: {old_error}", proc.chain\n                )\n            else:\n                error = RuntimeError(f"Chain {proc.chain} failed.")\n            raise error from old_error\n        elif msg[0] == "progress":\n            proc._current_stage = msg[1]\n            proc._current_beta = msg[2]\n            return (proc, "progress", msg[1], msg[2])\n        elif msg[0] == "done":\n            stage, beta, tempered_posterior, var_info, variables, sample_stats, sample_settings = (\n                cloudpickle.loads(msg[1])\n            )\n            return (\n                proc,\n                "done",\n                stage,\n                beta,\n                tempered_posterior,\n                var_info,\n                variables,\n                sample_stats,\n                sample_settings,\n            )\n        else:\n            raise ValueError("Sampler sent bad message: " + msg[0])\n\n    @staticmethod\n    def terminate_all(processes, patience=2):\n        """Terminate all worker processes."""\n        for process in processes:\n            try:\n                process.abort()\n            except Exception:\n                pass\n\n        start_time = time.time()\n        try:\n            for process in processes:\n                timeout = time.time() + patience - start_time\n                if timeout < 0:\n                    raise multiprocessing.TimeoutError()\n                process.join(timeout)\n        except multiprocessing.TimeoutError:\n            logger.warning(\n                "Chain processes did not terminate as expected. Terminating forcefully..."\n            )\n            for process in processes:\n                process.terminate()\n            for process in processes:\n                process.join()\n\n\nclass ParallelSMCSampler:\n    """Parallel sampler for SMC chains."""\n\n    def __init__(\n        self,\n        *,\n        kernel: SMC_KERNEL,\n        chains: int,\n        cores: int,\n        rngs: Sequence[np.random.Generator],\n        start_points: list[dict[str, np.ndarray] | None],\n        mp_ctx: multiprocessing.context.BaseContext,\n        progressbar: bool = True,\n        progressbar_theme: Theme | None = default_progress_theme,\n        blas_cores: int | None = None,\n    ):\n        if any(len(arg) != chains for arg in [rngs, start_points]):\n            raise ValueError(f"Number of rngs and start_points must be {chains}.")\n\n        self._kernel = kernel\n        kernel_pickled = cloudpickle.dumps(kernel, protocol=-1)\n        start_points_pickled = [\n            cloudpickle.dumps(start, protocol=-1) if start is not None else None\n            for start in start_points\n        ]\n\n        self._samplers = [\n            SMCProcessAdapter(\n                kernel_pickled,\n                chain,\n                rng,\n                start_pickled,\n                mp_ctx,\n                blas_cores,\n            )\n            for chain, rng, start_pickled in zip(range(chains), rngs, start_points_pickled)\n        ]\n\n        self._inactive = self._samplers.copy()\n        self._finished: list[SMCProcessAdapter] = []\n        self._active: list[SMCProcessAdapter] = []\n        self._max_active = cores\n\n        self._in_context = False\n\n        self._progressbar = progressbar\n        self._progressbar_theme = progressbar_theme\n        self._chains = chains\n\n    def _make_active(self):\n        """Start inactive processes up to the maximum number of active processes."""\n        while self._inactive and len(self._active) < self._max_active:\n            proc = self._inactive.pop(0)\n            proc.start()\n            self._active.append(proc)\n\n    def __iter__(self):\n        """Iterate over SMC results."""\n        if not self._in_context:\n            raise ValueError("Use ParallelSMCSampler as context manager.")\n\n        self._make_active()\n\n        with SMCProgressBarManager(\n            kernel=self._kernel,\n            chains=self._chains,\n            progressbar=self._progressbar,\n            progressbar_theme=self._progressbar_theme,\n        ) as progress_manager:\n            chain_betas = {proc.chain: 0.0 for proc in self._samplers}\n\n            while self._active:\n                result = SMCProcessAdapter.recv_message(self._active, timeout=3600)\n                proc = result[0]\n                msg_type = result[1]\n\n                if msg_type == "progress":\n                    stage, beta = result[2], result[3]\n                    old_beta = chain_betas[proc.chain]\n                    chain_betas[proc.chain] = beta\n\n                    progress_manager.update(proc.chain, stage, beta, old_beta)\n                    proc.continue_sampling()\n\n                elif msg_type == "done":\n                    (\n                        stage,\n                        beta,\n                        tempered_posterior,\n                        var_info,\n                        variables,\n                        sample_stats,\n                        sample_settings,\n                    ) = result[2:]\n\n                    progress_manager.update(proc.chain, stage, beta, is_last=True)\n\n                    proc.join()\n                    self._active.remove(proc)\n                    self._finished.append(proc)\n                    self._make_active()\n\n                    yield SMCResult(\n                        proc.chain,\n                        True,\n                        stage,\n                        beta,\n                        tempered_posterior,\n                        var_info,\n                        variables,\n                        sample_stats,\n                        sample_settings,\n                    )\n\n    def __enter__(self):\n        """Enter the context manager."""\n        self._in_context = True\n        return self\n\n    def __exit__(self, *args):\n        """Exit the context manager."""\n        SMCProcessAdapter.terminate_all(self._samplers)\n',
            'pymc/smc/sampling.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nimport logging\nimport time\n\nfrom typing import Any\n\nimport numpy as np\n\nfrom arviz import InferenceData\nfrom rich.theme import Theme\n\nimport pymc\n\nfrom pymc.backends.arviz import dict_to_dataset, to_inference_data\nfrom pymc.backends.base import MultiTrace\nfrom pymc.model import Model, modelcontext\nfrom pymc.progress_bar import SMCProgressBarManager, default_progress_theme\nfrom pymc.sampling.mcmc import setup_cores_blas_cores\nfrom pymc.sampling.parallel import _cpu_count, _initialize_multiprocessing_context\nfrom pymc.smc.kernels import IMH\nfrom pymc.smc.parallel import ParallelSMCSampler\nfrom pymc.stats.convergence import log_warnings, run_convergence_checks\nfrom pymc.util import (\n    RandomState,\n    _get_seeds_per_chain,\n)\n\nlogger = logging.getLogger(__name__)\n\n\ndef sample_smc(\n    draws=2000,\n    kernel=IMH,\n    *,\n    start=None,\n    model=None,\n    random_seed: RandomState = None,\n    chains=None,\n    cores=None,\n    blas_cores: int | str | None = None,\n    compute_convergence_checks=True,\n    return_inferencedata=True,\n    idata_kwargs=None,\n    progressbar=True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    compile_kwargs: dict | None = None,\n    mp_ctx=None,\n    **kernel_kwargs,\n) -> InferenceData | MultiTrace:\n    r"""\n    Sequential Monte Carlo based sampling.\n\n    Parameters\n    ----------\n    draws : int, default 2000\n        The number of samples to draw from the posterior (i.e. last stage). And also the number of\n        independent chains. Defaults to 2000.\n    kernel : SMC_kernel, optional\n        SMC kernel used. Defaults to :class:`pymc.smc.smc.IMH` (Independent Metropolis Hastings)\n    start : dict or array of dict, optional\n        Starting point in parameter space. It should be a list of dict with length `chains`.\n        When None (default) the starting point is sampled from the prior distribution.\n    model : Model (optional if in ``with`` context).\n    random_seed :  int, array_like of int, RandomState or numpy_Generator, optional\n        Random seed(s) used by the sampling steps. If a list, tuple or array of ints\n        is passed, each entry will be used to seed each chain. A ValueError will be\n        raised if the length does not match the number of chains.\n    chains : int, optional\n        The number of chains to sample. Running independent chains is important for some\n        convergence statistics. If ``None`` (default), then set to either ``cores`` or 2, whichever\n        is larger.\n    cores : int, default None\n        The number of chains to run in parallel. If ``None``, set to the number of CPUs in the\n        system.\n    blas_cores: int or "auto" or None, default = "auto"\n        The total number of threads blas and openmp functions should use during sampling.\n        Setting it to "auto" will ensure that the total number of active blas threads is the\n        same as the `cores` argument. If set to an integer, the sampler will try to use that total\n        number of blas threads. If `blas_cores` is not divisible by `cores`, it might get rounded\n        down. If set to None, this will keep the default behavior of whatever blas implementation\n        is used at runtime.\n    compute_convergence_checks : bool, default True\n        Whether to compute sampler statistics like ``R hat`` and ``effective_n``.\n        Defaults to ``True``.\n    return_inferencedata : bool, default True\n        Whether to return the trace as an InferenceData (True) object or a MultiTrace (False).\n        Defaults to ``True``.\n    idata_kwargs : dict, optional\n        Keyword arguments for :func:`pymc.to_inference_data`.\n    progressbar : bool, optional, default True\n        Whether or not to display a progress bar in the command line.\n    progressbar_theme : Theme, optional\n        Custom theme for progress bar. Defaults to the standard PyMC progress bar theme.\n    compile_kwargs: dict, optional\n        Keyword arguments to pass to pytensor.function\n    mp_ctx : multiprocessing.context or str, optional\n        Multiprocessing context for parallel chains. Can be a context object or a string\n        ("fork", "spawn", or "forkserver"). If None, defaults to "fork" on macOS ARM and\n        "forkserver" on other macOS systems, and the system default elsewhere.\n\n    **kernel_kwargs : dict, optional\n        Keyword arguments passed to the SMC_kernel. The default IMH kernel takes the following keywords:\n\n        threshold : float, default 0.5\n          Determines the change of beta from stage to stage, i.e. indirectly the number of stages,\n          the higher the value of `threshold` the higher the number of stages. Defaults to 0.5.\n          It should be between 0 and 1.\n        correlation_threshold : float, default 0.01\n            The lower the value the higher the number of MCMC steps computed automatically.\n            Defaults to 0.01. It should be between 0 and 1.\n\n        Additional keyword arguments for other kernels should be checked in the respective docstrings.\n\n    Notes\n    -----\n    SMC works by moving through successive stages. At each stage the inverse temperature\n    :math:`\\beta` is increased a little bit (starting from 0 up to 1). When :math:`\\beta` = 0\n    we have the prior distribution and when :math:`\\beta = 1` we have the posterior distribution.\n    So in more general terms, we are always computing samples from a tempered posterior that we can\n    write as:\n\n    .. math::\n\n        p(\\theta \\mid y)_{\\beta} = p(y \\mid \\theta)^{\\beta} p(\\theta)\n\n    A summary of the algorithm is:\n\n     1. Initialize :math:`\\beta` at zero and stage at zero.\n     2. Generate N samples :math:`S_{\\beta}` from the prior (because when :math `\\beta = 0` the\n        tempered posterior is the prior).\n     3. Increase :math:`\\beta` in order to make the effective sample size equal some predefined\n        value (we use :math:`Nt`, where :math:`t` is 0.5 by default).\n     4. Compute a set of N importance weights W. The weights are computed as the ratio of the\n        likelihoods of a sample at stage i+1 and stage i.\n     5. Obtain :math:`S_{w}` by re-sampling according to W.\n     6. Use W to compute the mean and covariance for the proposal distribution, a MvNormal.\n     7. Run N independent MCMC chains, starting each one from a different sample\n        in :math:`S_{w}`. For the IMH kernel, the mean of the proposal distribution is the\n        mean of the previous posterior stage and not the current point in parameter space.\n     8. The N chains are run until the autocorrelation with the samples from the previous stage\n        stops decreasing given a certain threshold.\n     9. Repeat from step 3 until :math:`\\beta \\ge 1`.\n     10. The final result is a collection of N samples from the posterior.\n\n\n    References\n    ----------\n    .. [Minson2013] Minson, S. E., Simons, M., and Beck, J. L. (2013).\n        "Bayesian inversion for finite fault earthquake source models I- Theory and algorithm."\n        Geophysical Journal International, 2013, 194(3), pp.1701-1726.\n        `link <https://gji.oxfordjournals.org/content/194/3/1701.full>`__\n\n    .. [Ching2007] Ching, J., and Chen, Y. (2007).\n        "Transitional Markov Chain Monte Carlo Method for Bayesian Model Updating, Model Class\n        Selection, and Model Averaging." J. Eng. Mech., 2007, 133(7), pp. 816-832. doi:10.1061/(ASCE)0733-9399(2007)133:7(816).\n        `link <http://ascelibrary.org/doi/abs/10.1061/%28ASCE%290733-9399\n        %282007%29133:7%28816%29>`__\n    """\n    if cores is None:\n        cores = _cpu_count()\n\n    if chains is None:\n        chains = max(2, cores)\n    else:\n        cores = min(chains, cores)\n\n    if compile_kwargs is None:\n        compile_kwargs = {}\n\n    kernel_kwargs["compile_kwargs"] = compile_kwargs\n\n    random_seed = _get_seeds_per_chain(random_state=random_seed, chains=chains)\n\n    model = modelcontext(model)\n\n    logger.info("Initializing SMC sampler...")\n\n    mp_ctx = _initialize_multiprocessing_context(mp_ctx)\n    joined_blas_limiter, cores, num_blas_cores_per_worker = setup_cores_blas_cores(\n        blas_cores, chains, cores, mp_ctx\n    )\n\n    t1 = time.time()\n\n    rngs = [np.random.default_rng(seed) for seed in random_seed]\n\n    with model:\n        smc_kernel = kernel(\n            draws=draws,\n            start=None,\n            model=model,\n            random_seed=rngs[0].integers(2**30),\n            **kernel_kwargs,\n        )\n\n    # Prepare start points for each chain\n    start_points: list[dict | None]\n    if start is None:\n        start_points = [None] * chains\n    elif isinstance(start, dict):\n        start_points = [start] * chains\n    else:\n        if len(start) != chains:\n            raise ValueError(f"Number of start dicts must match number of chains ({chains})")\n        start_points = start\n\n    parallel = cores > 1 and chains > 1\n\n    traces = []\n    sample_stats = []\n    sample_settings = []\n\n    if parallel:\n        logger.info(\n            f"Sampling {chains} chain{\'s\' if chains > 1 else \'\'} "\n            f"in {cores} job{\'s\' if cores > 1 else \'\'}"\n        )\n\n        results = []\n        with joined_blas_limiter():\n            with ParallelSMCSampler(\n                kernel=smc_kernel,\n                chains=chains,\n                cores=cores,\n                rngs=rngs,\n                start_points=start_points,\n                progressbar=progressbar,\n                progressbar_theme=progressbar_theme,\n                mp_ctx=mp_ctx,\n                blas_cores=num_blas_cores_per_worker,\n            ) as sampler:\n                for result in sampler:\n                    results.append(result)\n\n        chain_results: list[list] = [[] for _ in range(chains)]\n        for result in results:\n            chain_results[result.chain].append(result)\n\n        for chain_idx, chain_samples in enumerate(chain_results):\n            if not chain_samples:\n                raise RuntimeError(\n                    f"Chain {chain_idx} did not produce any results. "\n                    "This indicates a failure in parallel sampling."\n                )\n            final_result = chain_samples[-1]\n            trace = _build_trace_from_kernel_state(\n                final_result.tempered_posterior,\n                final_result.var_info,\n                final_result.variables,\n                chain_idx,\n                model,\n            )\n            traces.append(trace)\n\n            sample_stats.append(final_result.sample_stats)\n            sample_settings.append(final_result.sample_settings)\n\n    else:\n        logger.info(\n            f"Sampling {chains} chain{\'s\' if chains > 1 else \'\'}{\' sequentially\' if chains > 1 else \'\'}"\n        )\n        with joined_blas_limiter():\n            _sample_smc_sequentially(\n                kernel=smc_kernel,\n                chains=chains,\n                rngs=rngs,\n                start_points=start_points,\n                model=model,\n                progressbar=progressbar,\n                progressbar_theme=progressbar_theme,\n                traces=traces,\n                sample_stats=sample_stats,\n                sample_settings=sample_settings,\n            )\n\n    trace = MultiTrace(traces)\n\n    _t_sampling = time.time() - t1\n    _, idata = _save_sample_stats(\n        sample_settings,\n        sample_stats,\n        chains,\n        trace,\n        return_inferencedata,\n        _t_sampling,\n        idata_kwargs,\n        model,\n    )\n\n    if compute_convergence_checks:\n        if idata is None:\n            idata = to_inference_data(trace, log_likelihood=False)\n        warns = run_convergence_checks(idata, model)\n        trace.report._add_warnings(warns)\n        log_warnings(warns)\n\n    if return_inferencedata:\n        assert idata is not None\n        return idata\n    return trace\n\n\ndef _save_sample_stats(\n    sample_settings,\n    sample_stats,\n    chains,\n    trace: MultiTrace,\n    return_inferencedata: bool,\n    _t_sampling,\n    idata_kwargs,\n    model: Model,\n) -> tuple[Any | None, InferenceData | None]:\n    sample_settings_dict = sample_settings[0]\n    sample_settings_dict["_t_sampling"] = _t_sampling\n    sample_stats_dict = sample_stats[0]\n\n    if chains > 1:\n        # Collect the stat values from each chain in a single list\n        for stat in sample_stats[0].keys():\n            value_list = []\n            for chain_sample_stats in sample_stats:\n                value_list.append(chain_sample_stats[stat])\n            sample_stats_dict[stat] = value_list\n\n    idata: InferenceData | None = None\n    if not return_inferencedata:\n        for stat, value in sample_stats_dict.items():\n            setattr(trace.report, stat, value)\n        for stat, value in sample_settings_dict.items():\n            setattr(trace.report, stat, value)\n    else:\n        for stat, value in sample_stats_dict.items():\n            if chains > 1:\n                # Different chains might have more iteration steps, leading to a\n                # non-square `sample_stats` dataset, we cast as `object` to avoid\n                # numpy ragged array deprecation warning\n                sample_stats_dict[stat] = np.array(value, dtype=object)\n            else:\n                sample_stats_dict[stat] = np.array(value)\n\n        sample_stats = dict_to_dataset(\n            sample_stats_dict,\n            attrs=sample_settings_dict,\n            library=pymc,\n        )\n\n        ikwargs: dict[str, Any] = {"model": model}\n        if idata_kwargs is not None:\n            ikwargs.update(idata_kwargs)\n        idata = to_inference_data(trace, **ikwargs)\n        idata = InferenceData(**idata, sample_stats=sample_stats)  # type: ignore[arg-type]\n\n    return sample_stats, idata\n\n\ndef _build_trace_from_kernel_state(\n    tempered_posterior: np.ndarray,\n    var_info: dict,\n    variables: list,\n    chain: int,\n    model: Model,\n):\n    """Build a trace from kernel state.\n\n    This allows trace building to happen in the main process rather than workers.\n\n    Parameters\n    ----------\n    tempered_posterior : ndarray\n        The final particle positions\n    var_info : dict\n        Dictionary of variable info {var.name: (shape, size)}\n    variables : list\n        List of model variables\n    chain : int\n        Chain index\n    model : Model\n        PyMC model for trace setup\n\n    Returns\n    -------\n    NDArray trace backend\n    """\n    from pymc.backends.ndarray import NDArray\n    from pymc.vartypes import discrete_types\n\n    length_pos = len(tempered_posterior)\n    varnames = [v.name for v in variables]\n\n    strace = NDArray(name=model.name, model=model)\n    strace.setup(length_pos, chain)\n\n    for i in range(length_pos):\n        value = []\n        size = 0\n        for var in variables:\n            shape, new_size = var_info[var.name]\n            var_samples = tempered_posterior[i][size : size + new_size]\n            # Round discrete variable samples\n            if var.dtype in discrete_types:\n                var_samples = np.round(var_samples).astype(var.dtype)\n            value.append(var_samples.reshape(shape))\n            size += new_size\n        strace.record(point=dict(zip(varnames, value)), in_warmup=False)\n\n    return strace\n\n\ndef _sample_smc_sequentially(\n    *,\n    kernel,\n    chains: int,\n    rngs: list[np.random.Generator],\n    start_points: list[dict | None],\n    model: Model,\n    progressbar: bool,\n    progressbar_theme: Theme | None,\n    traces: list,\n    sample_stats: list,\n    sample_settings: list,\n):\n    """Sample all SMC chains sequentially.\n\n    Parameters\n    ----------\n    kernel: SMC_KERNEL instance\n        An initialized SMC kernel (with compiled functions)\n    chains: int\n        Total number of chains to sample\n    rngs: list of random Generators\n        A list of random number generators, one for each chain\n    start_points: list\n        Starting points for each chain\n    model: Model\n        The PyMC model\n    progressbar: bool\n        Whether to show progress bar\n    progressbar_theme: Theme\n        Progress bar theme\n    traces: list\n        List to append trace results to\n    sample_stats: list\n        List to append sample_stats to\n    sample_settings: list\n        List to append sample_settings to\n    """\n    with SMCProgressBarManager(\n        kernel=kernel,\n        chains=chains,\n        progressbar=progressbar,\n        progressbar_theme=progressbar_theme,\n    ) as progress_manager:\n        for i in range(chains):\n            kernel.initialize(start_points[i], rngs[i])\n\n            stage = 0\n            chain_sample_stats: dict[str, list] = {stat: [] for stat in kernel.stats_dtypes_shapes}\n\n            while kernel.beta < 1:\n                old_beta = kernel.beta\n                kernel.update_beta_and_weights()\n\n                progress_manager.update(\n                    chain_idx=i, stage=stage, beta=kernel.beta, old_beta=old_beta, is_last=False\n                )\n\n                for stat, value in kernel.step().items():\n                    chain_sample_stats[stat].append(value)\n\n                stage += 1\n\n            progress_manager.update(chain_idx=i, stage=stage, beta=kernel.beta, is_last=True)\n\n            trace = _build_trace_from_kernel_state(\n                tempered_posterior=kernel.tempered_posterior,\n                var_info=kernel.var_info,\n                variables=kernel.variables,\n                chain=i,\n                model=model,\n            )\n\n            traces.append(trace)\n            sample_stats.append(chain_sample_stats)\n            sample_settings.append(kernel.sample_settings())\n',
            'tests/progress_bar/test_manager.py': '#   Copyright 2025 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nimport pytest\n\nimport pymc as pm\n\nfrom pymc.progress_bar import MCMCProgressBarManager\n\n\ndef test_progressbar_nested_compound():\n    """Regression test for https://github.com/pymc-devs/pymc/issues/7721"""\n    with pm.Model():\n        a = pm.Poisson("a", mu=10)\n        b = pm.Binomial("b", n=a, p=0.8)\n        c = pm.Poisson("c", mu=11)\n        d = pm.Dirichlet("d", a=[c, b])\n\n        step = pm.CompoundStep(\n            [\n                pm.CompoundStep([pm.Metropolis(a), pm.Metropolis(b), pm.Metropolis(c)]),\n                pm.NUTS([d]),\n            ]\n        )\n\n        kwargs = {\n            "draws": 10,\n            "tune": 10,\n            "chains": 2,\n            "compute_convergence_checks": False,\n            "step": step,\n        }\n\n        for cores in (1, 2):\n            pm.sample(**kwargs, cores=cores, progressbar=True)\n            pm.sample(**kwargs, cores=cores, progressbar="combined")\n            pm.sample(**kwargs, cores=cores, progressbar="split")\n            pm.sample(**kwargs, cores=cores, progressbar=False)\n\n\nclass TestProgressBarManagerConfiguration:\n    @pytest.fixture\n    def step_method(self):\n        with pm.Model():\n            x = pm.Normal("x")\n            step = pm.NUTS([x])\n        return step\n\n    def test_init_split_mode(self, step_method):\n        manager = MCMCProgressBarManager(\n            step_method=step_method,\n            chains=2,\n            draws=100,\n            tune=50,\n            progressbar=True,\n        )\n        assert manager.combined_progress is False\n        assert manager.full_stats is True\n        assert manager._show_progress is True\n        assert manager.chains == 2\n        assert manager.total_draws == 150\n\n    def test_init_combined_mode(self, step_method):\n        manager = MCMCProgressBarManager(\n            step_method=step_method,\n            chains=2,\n            draws=100,\n            tune=50,\n            progressbar="combined",\n        )\n        assert manager.combined_progress is True\n        assert manager.full_stats is False\n\n    def test_init_combined_stats_mode(self, step_method):\n        manager = MCMCProgressBarManager(\n            step_method=step_method,\n            chains=2,\n            draws=100,\n            tune=50,\n            progressbar="combined+stats",\n        )\n        assert manager.combined_progress is True\n        assert manager.full_stats is True\n\n    def test_init_split_stats_mode(self, step_method):\n        manager = MCMCProgressBarManager(\n            step_method=step_method,\n            chains=2,\n            draws=100,\n            tune=50,\n            progressbar="split+stats",\n        )\n        assert manager.combined_progress is False\n        assert manager.full_stats is True\n\n    def test_init_disabled(self, step_method):\n        manager = MCMCProgressBarManager(\n            step_method=step_method,\n            chains=2,\n            draws=100,\n            tune=50,\n            progressbar=False,\n        )\n        assert manager._show_progress is False\n\n    def test_invalid_progressbar_value(self, step_method):\n        with pytest.raises(ValueError, match="Invalid value for `progressbar`"):\n            MCMCProgressBarManager(\n                step_method=step_method,\n                chains=2,\n                draws=100,\n                tune=50,\n                progressbar="invalid",\n            )\n',
            'tests/progress_bar/test_marimo.py': '#   Copyright 2025 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nfrom unittest.mock import patch\n\nimport pytest\n\nimport pymc as pm\n\nfrom pymc.progress_bar import MCMCProgressBarManager\nfrom pymc.progress_bar.marimo_progress import MarimoProgressBackend\n\n\nclass TestMarimoProgressBackend:\n    @pytest.fixture(autouse=True)\n    def require_marimo(self):\n        pytest.importorskip("marimo")\n\n    @pytest.fixture\n    def step_method(self):\n        with pm.Model():\n            x = pm.Normal("x")\n            step = pm.NUTS([x])\n        return step\n\n    def test_init_split_mode(self, step_method):\n        with patch("pymc.progress_bar.progress.in_marimo_notebook", return_value=True):\n            manager = MCMCProgressBarManager(\n                step_method=step_method,\n                chains=2,\n                draws=100,\n                tune=50,\n                progressbar=True,\n            )\n            assert isinstance(manager._backend, MarimoProgressBackend)\n\n    def test_init_combined_mode(self, step_method):\n        with patch("pymc.progress_bar.progress.in_marimo_notebook", return_value=True):\n            manager = MCMCProgressBarManager(\n                step_method=step_method,\n                chains=2,\n                draws=100,\n                tune=50,\n                progressbar="combined",\n            )\n            assert isinstance(manager._backend, MarimoProgressBackend)\n            assert manager.combined_progress is True\n            assert manager.full_stats is False\n\n    def test_render_html_structure(self, step_method):\n        with patch("pymc.progress_bar.progress.in_marimo_notebook", return_value=True):\n            manager = MCMCProgressBarManager(\n                step_method=step_method,\n                chains=2,\n                draws=100,\n                tune=50,\n                progressbar=True,\n            )\n            backend = manager._backend\n            assert isinstance(manager._backend, MarimoProgressBackend)\n\n            backend._chain_state = [\n                {"completed": 50, "total": 150, "failing": False, "stats": {}},\n                {"completed": 75, "total": 150, "failing": True, "stats": {"divergences": 1}},\n            ]\n            backend._start_times = [0, 0]\n\n            html = backend._render_html()\n\n            assert "pymc-progress-table" in html\n            assert "pymc-progress-bar" in html\n            assert "failing" in html\n\n    def test_render_html_with_stats(self, step_method):\n        with patch("pymc.progress_bar.progress.in_marimo_notebook", return_value=True):\n            manager = MCMCProgressBarManager(\n                step_method=step_method,\n                chains=1,\n                draws=100,\n                tune=50,\n                progressbar="split+stats",\n            )\n            backend = manager._backend\n            assert isinstance(manager._backend, MarimoProgressBackend)\n\n            backend._task_state = [\n                {\n                    "completed": 50,\n                    "total": 150,\n                    "failing": False,\n                    "stats": {"step_size": 0.25, "divergences": 0},\n                },\n            ]\n            backend._start_times = [0]\n\n            html = backend._render_html()\n\n            assert "0.25" in html or "Step" in html\n',
        }
